// LESSON: JavaFX Controls - Reference Page 2.
// You will learn: Configure controls, choices, sliders, and observable selection state.
import javafx.application.Application;
import javafx.collections.FXCollections;
import javafx.collections.ObservableList;
import javafx.geometry.Insets;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.CheckBox;
import javafx.scene.control.ComboBox;
import javafx.scene.control.Label;
import javafx.scene.control.ListView;
import javafx.scene.control.TextArea;
import javafx.scene.control.TextField;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class JavaFxControlsReference extends Application {
  public static void main(String[] args) {
    launch(args);
  }

  @Override
  public void start(Stage stage) {
    VBox root = new VBox(10);
    root.setPadding(new Insets(12));
    root.getChildren().addAll(textControls(), choiceControls(), listViewControl());
    stage.setScene(new Scene(root, 460, 420));
    stage.setTitle("Controls");
    stage.show();
  }

  private VBox textControls() {
    Label output = new Label("EXAMPLE 1: TextField and TextArea");
    TextField name = new TextField();
    TextArea notes = new TextArea();
    Button copy = new Button("Show text");
    copy.setOnAction(e -> output.setText(name.getText() + ": " + notes.getText()));
    return new VBox(5, output, name, notes, copy);
  }

  private VBox choiceControls() {
    Label status = new Label("EXAMPLE 2: CheckBox and ComboBox");
    CheckBox member = new CheckBox("Member");
    ComboBox<String> level = new ComboBox<>();
    level.getItems().addAll("Basic", "Middle", "Advanced");
    Button read = new Button("Read choice");
    read.setOnAction(e -> status.setText(member.isSelected() + " / " + level.getValue()));
    return new VBox(5, status, member, level, read);
  }

  private VBox listViewControl() {
    ObservableList<String> names = FXCollections.observableArrayList("Ada", "Bo", "Cia");
    ListView<String> list = new ListView<>(names);
    Label selected = new Label("EXAMPLE 3: ListView selection");
    Button show = new Button("Show selected");
    show.setOnAction(e -> selected.setText("Selected: " + list.getSelectionModel().getSelectedItem()));
    return new VBox(5, selected, list, show);
  }
}
